enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

interface Drawable:
    def draw(self) -> str
    ...

interface Resizable:
    def resize(self, factor: float) -> None
    ...

@abstract
class Shape(Drawable):
    color: Color

    def __init__(self, color: Color):
        self.color = color

    @virtual
    def describe(self) -> str:
        return "A generic shape"

    @abstract
    def area(self) -> float

    def describe_color(self) -> str:
        return f"Colored {self.color.name}"

    @virtual
    def draw(self) -> str:
        return f"A {self.describe_color()} shape"

class Rectangle(Shape, Resizable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle: {self.width}x{self.height}"

    def resize(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def draw(self) -> str:
        return f"[Drawable] {self.describe_color()} - {self.describe()}"

