from shapes import Shape

struct Dimensions:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

class ShapeBox:
    inner: Shape

    def __init__(self, shape: Shape):
        self.inner = shape

    def get_area(self) -> float:
        return self.inner.area()

    def get_description(self) -> str:
        return self.inner.describe()

