from shapes import Shape, Rectangle, Color

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total

def find_largest(shapes: list[Shape]) -> Shape:
    if len(shapes) == 0:
        raise ValueError("Empty list")

    largest: Shape = shapes[0]
    max_area: float = largest.area()

    i: int = 1
    while i < len(shapes):
        area: float = shapes[i].area()
        if area > max_area:
            max_area = area
            largest = shapes[i]
        i = i + 1

    return largest

def create_square(side: float, color: Color) -> Rectangle:
    return Rectangle(side, side, color)
